template<class T, class HashFunctionType>
class HashSet {
  vector<list<T>> m_table;
  HashFunctionType m_hash;
public:
  HashSet(int size, HashFunctionType hash): m_table(size), m_hash(hash) {}
  bool contains(const T& e) const {
    int i = m_hash(e);
    if (i < 0 || i >= (int)m_table.size()) throw HashOutOfRange();
    return count(m_table[i].begin(), m_table[i].end(), e) > 0;
  }
  void insert(const T& e){ if(!contains(e)) m_table[m_hash(e)].push_back(e); }
  void remove(const T& e){ if(contains(e)) m_table[m_hash(e)].remove(e); }
};

