ADDRESS_SUFFIXES = ['Street', 'Avenue', 'Road']

def starts_with_address(words):
    head = words[:4]
    return (len(head) if head and head[0].isdigit()
            and any(head[-1] == s for s in ADDRESS_SUFFIXES) else None)

def search_address(line):
    w = line.split()
    return [(i, starts_with_address(w[i:])) for i in range(len(w))
            if starts_with_address(w[i:]) is not None]

def find_killer(line, context):
    w = line.split()
    return [" ".join(w[max(0, i - context): i + length + context + 1])
            for i, length in search_address(line)]

template<class V>
class Graph {
  set<V> vertices; vector<Edge<V>> edges;
public:
  bool containsVertex(const V& v) const { return vertices.count(v) > 0; }
  bool addVertex(const V& v){ if(containsVertex(v)) return false; vertices.insert(v); return true; }
  bool containsEdge(const V& a,const V& b) const {
    Edge<V> e(a,b);
    for(const Edge<V>& x : edges) if(x==e) return true;
    return false; }
  bool addEdge(const V& a,const V& b){
    if(!containsVertex(a)||!containsVertex(b)||a==b||containsEdge(a,b)) return false;
    edges.push_back(Edge<V>(a,b)); return true; }
  Graph& operator+=(const Graph& o){
    for(const V& v : o.vertices) addVertex(v);
    for(const Edge<V>& e : o.edges) addEdge(e.first(), e.second());
    return *this; }
};
template<class V>
Graph<V> operator+(const Graph<V>& a,const Graph<V>& b){ Graph<V> r(a); r += b; return r; }

