class Ship {
  static const int MAX_SIZE = 12, MIN_WARRIORS = 5;
  unique_ptr<Warrior> m_captain;
  vector<shared_ptr<Sailor>> m_sailors;
public:
  Ship(unique_ptr<Warrior> captain): m_captain(std::move(captain)) {}
  Ship(const Ship&) = delete;
  Ship& operator=(const Ship&) = delete;
  void addSailor(const shared_ptr<Sailor>& s){
    if(m_sailors.size() >= MAX_SIZE) throw ShipIsFull();
    m_sailors.push_back(s); }
  bool canSail() const {
    int n = 0;
    for(const auto& s : m_sailors) if(dynamic_cast<Warrior*>(s.get())) ++n;
    if(n < MIN_WARRIORS) throw TooFewWarriors();
    return true; }
};

template<class T, class Function>
set<set<T>> groupBy(const set<T>& input, Function f){
  map<int, set<T>> groups;
  for(const T& e : input) groups[f(e)].insert(e);
  set<set<T>> result;
  for(auto& g : groups) result.insert(std::move(g.second));
  return result;
}

