class NoMoreBlocks : public std::exception {
public: const char* what() const noexcept override { return "No more blocks"; }
};
template<class T>
class MemManager {
  const int m_numBlocks, m_blockSize;
  T* blocks; bool* inUse;
public:
  MemManager(int n, int s): m_numBlocks(n), m_blockSize(s) {
    if(n<=0||s<=0) throw std::invalid_argument("positive only");
    blocks = new T[n*s];
    try { inUse = new bool[n](); }
    catch(...) { delete[] blocks; throw; }
  }
  ~MemManager(){ delete[] blocks; delete[] inUse; }
  T* acquire(){
    for(int i=0;i<m_numBlocks;++i)
      if(!inUse[i]){ inUse[i]=true; return blocks + i*m_blockSize; }
    throw NoMoreBlocks(); }
  void release(const T* b){ inUse[(b - blocks)/m_blockSize] = false; }
};
