def merge_lists(a, b):
    i = j = 0; out = []
    while i < len(a) and j < len(b):
        if a[i] < b[j]: out.append(a[i]); i += 1
        else:           out.append(b[j]); j += 1
    out.extend(a[i:]); out.extend(b[j:])
    return out

def reduce(init, l, f):
    result = init
    for e in l:
        result = f(result, e)
    return result

def merge_lists_in_path(path):
    with open(path) as f:
        lists = [[int(x) for x in line.split()] for line in f]
    return reduce([], lists, merge_lists)

