template<class T>
class CyclicBuffer {
  T* data; int cap; int head, tail;
public:
  explicit CyclicBuffer(int maxSize): data(new T[maxSize+1]), cap(maxSize+1), head(0), tail(0) {}
  ~CyclicBuffer(){ delete[] data; }
  bool isFull() const { return (tail+1)%cap == head; }
  bool isEmpty() const { return head == tail; }
  void push(const T& x){ if(isFull()) throw FullBuffer(); data[tail]=x; tail=(tail+1)%cap; }
  T pop(){ if(isEmpty()) throw EmptyBuffer(); T r=data[head]; head=(head+1)%cap; return r; }
  int size() const { return ((tail-head)+cap)%cap; }
};
// A copy ctor and assignment ARE required and must be non-default: the class owns a raw T*, so a shallow copy would share/double-free the buffer.

Iterator begin() const { return Iterator(head, *this); }
Iterator end()   const { return Iterator(tail, *this); }
class Iterator {
  int index; const CyclicBuffer<T>& buf;
  Iterator(int i, const CyclicBuffer<T>& b): index(i), buf(b) {}
  friend class CyclicBuffer;
public:
  Iterator& operator++(){ index = (index+1)%buf.cap; return *this; }
  bool operator!=(const Iterator& o) const { return &buf != &o.buf || index != o.index; }
  const T& operator*() const { return buf.data[index]; }
};

class Area {
  map<string, unique_ptr<Animal>> animals;
public:
  void addAnimal(unique_ptr<Animal> a){ animals[a->getName()] = std::move(a); }
  virtual bool hasAnimal(const string& n) const { return animals.count(n) > 0; }
  virtual unique_ptr<Animal> removeAnimal(const string& n){
    if(!Area::hasAnimal(n)) throw std::runtime_error("not found");
    auto it = animals.find(n);
    unique_ptr<Animal> a = std::move(it->second);
    animals.erase(it); return a; }
  virtual float getTotalWaterConsumption() const {
    float t=0; for(auto& p : animals) t += p.second->getWaterConsumption(); return t; }
};
class SpecialArea : public Area {          // Composite
  vector<unique_ptr<Area>> subAreas;
public:
  bool hasAnimal(const string& n) const override {
    if(Area::hasAnimal(n)) return true;
    for(auto& s : subAreas) if(s->hasAnimal(n)) return true;
    return false; }
  void addArea(unique_ptr<Area> a){ subAreas.push_back(std::move(a)); }
  float getTotalWaterConsumption() const override {
    float t = Area::getTotalWaterConsumption();
    for(auto& s : subAreas) t += s->getTotalWaterConsumption(); return t; }
};
// Pattern: Composite.

template<class T>
class cow_ptr {
  T* data; size_t* ref_count;
  void detach(){ if(*ref_count > 1){ --(*ref_count); data = new T(*data); ref_count = new size_t(1); } }
public:
  explicit cow_ptr(T* p): data(p), ref_count(new size_t(1)) {}
  cow_ptr(const cow_ptr& o): data(o.data), ref_count(o.ref_count) { ++(*ref_count); }
  cow_ptr& operator=(const cow_ptr& o){
    if(this != &o){
      if(--(*ref_count) == 0){ delete data; delete ref_count; }
      data = o.data; ref_count = o.ref_count; ++(*ref_count);
    } return *this; }
  ~cow_ptr(){ if(--(*ref_count) == 0){ delete data; delete ref_count; } }
  const T& operator*() const { return *data; }
  T& operator*(){ detach(); return *data; }
  size_t count() const { return *ref_count; }
};

template<class It,class Pred>
bool all_of(It first, It last, Pred p){ for(; first!=last; ++first) if(!p(*first)) return false; return true; }

template<class It,class Fn>
double calcAvg(It first, It last, Fn f){
  if(first==last) throw std::invalid_argument("empty");
  double sum=0; int n=0;
  for(It it=first; it!=last; ++it){ sum += f(*it); ++n; }
  return sum/n; }

double calcAreas(vector<shared_ptr<Shape>> shapes, int x){
  if(shapes.empty() || x<=0) throw std::invalid_argument("bad args");
  std::sort(shapes.begin(), shapes.end(),
            [](const auto& a, const auto& b){ return a->getArea() < b->getArea(); });
  return calcAvg(shapes.end()-x, shapes.end(),
                 [](const auto& s){ return s->getArea(); });
}

